export default {

	_normalizeUploadResponse(uploadRes) {
		const r = uploadRes?.data ?? uploadRes;

		const arr =
			Array.isArray(r) ? r :
			Array.isArray(r?.files) ? r.files :
			(r && typeof r === "object") ? [r] :
			[];

		// Require real attachment objects (path or signedPath)
		const good = arr.filter(x => x && (x.path || x.signedPath));

		if (!good.length) {
			console.log("Unexpected upload response:", uploadRes);
			throw new Error("Upload succeeded but did not return attachment path(s).");
		}

		return good;
	},

  async submitMember() {
    const first = inpFirstName.text.trim();
    const last  = inpLastName.text.trim();

    if (!first || !last) {
      showAlert("First and last name are required.", "warning");
      return;
    }

    // --- New validations based on your new workflow ---
    const wantsAgreement = inpCreateRelease.isChecked;

    // You mentioned:
    // - require facilitator if sending release
    // - require FilePicker1 selection if uploading paper release
    // I'm assuming you have inpUploadRelease checkbox and FilePicker1 widget.
    const uploadPaper = (typeof inpUploadRelease !== "undefined") ? inpUploadRelease.isChecked : false;

    if (wantsAgreement) {
      const facilitatorId =
        (typeof inpFacilitator !== "undefined")
          ? (inpFacilitator.selectedOptionValue || "").trim()
          : "";

      if (!facilitatorId) {
        showAlert("Please select a facilitator before creating an agreement.", "warning");
        return;
      }
    }

    // 1) Check duplicates
    const dup = await qCheckMemberDuplicate.run();
    if (dup && dup.length > 0) {
      const hit = dup[0];
      showAlert(
        `Member already exists (ID ${hit.member_id}). Please open the existing member instead of creating a new one.`,
        "error"
      );
      storeValue("memberDupes", dup);
      return;
    }

    // 2) Insert member
    const inserted = await qCreateMember.run();
    const memberId = inserted?.[0]?.member_id;
    if (!memberId) throw new Error("Member insert did not return member_id.");

		showAlert(`Member created (ID ${memberId}).`, "success");
    await storeValue("new_member_id", memberId);

    // 3) Agreement handling (Documenso vs Paper upload)
    let agRes = null;
		let triggerRes = null;

    if (wantsAgreement) {
      const facilitatorId =
        (typeof inpFacilitator !== "undefined") ? inpFacilitator.selectedOptionValue : null;

      // Decide signature method + status
      // - OpenSign => pending_signature
      // - Paper => pending_review
      const signatureMethod = uploadPaper ? "paper" : "documenso";
      const agreementStatus = uploadPaper ? "pending_review" : "pending_signature";

      await storeValue("selected_facilitator_id", facilitatorId);
      await storeValue("signature_method", signatureMethod);
      await storeValue("agreement_status", agreementStatus);
			await storeValue("evidence_json", null);

      if (uploadPaper) {
				const raw = FilePicker1?.files ?? [];
				console.log("FilePicker1.files raw:", raw);
				// Only keep real File-like objects
				const files = raw.filter((f) =>
					f &&
					typeof f === "object" &&
					typeof f.name === "string" &&
					typeof f.size === "number" &&
					f.size >= 0
				);

				if (!files.length) {
					showAlert("Please choose at least one valid file to upload for the paper agreement.", "warning");
					return;
				}

				// If there were invalid entries, surface it loudly (this is what you're hitting)
				if (files.length !== raw.length) {
					showAlert(
						`Some selected items were invalid (null/non-file). Remove them and re-select the file(s).`,
						"warning"
					);
					// Stop here so you don't get silent partial uploads
					return;
				}

				// Optional: guard against non-File objects
				const bad = files.find(f => typeof f !== "object" || !("name" in f) || !("size" in f));
				if (bad) {
